  // ==================== Initialization ====================

  function init() {

    applyTheme();

    const info = getInfo();
    if (!info) return;

    const categories = [

      getSetting("showStreaming") && buildStreaming(info),
      getSetting("showShow") && buildShow(info),
      getSetting("showAlt") && buildAlt(info),
      getSetting("showAnother") && buildAnother(info),
      getSetting("showSubs") && buildSubs(info),
      getSetting("showTorrent") && buildTorrent(info),
      getSetting("showDownload") && buildDownload(info),
      getSetting("showFun") && buildFun(info),
      getSetting("showFilmAdult") && buildFilmAdult(info),
      getSetting("showAdult") && buildAdult(info)

    ].filter(Boolean);

    createPopup(categories);

  }

  // Menunda inisialisasi agar elemen IMDB termuat dan JSON-LD tersedia.
  $(document).ready(() => setTimeout(init, 1000));
